        var context = TestHelper.CreateContext();
        context.Students.Add(new Student { FirstMidName = "Alice", LastName = "A", EnrollmentDate = DateTime.Parse("2020-09-01") });
        context.Students.Add(new Student { FirstMidName = "Bob", LastName = "B", EnrollmentDate = DateTime.Parse("2020-09-01") });
        context.Students.Add(new Student { FirstMidName = "Charlie", LastName = "C", EnrollmentDate = DateTime.Parse("2021-09-01") });
        context.SaveChanges();
        _controller = new HomeController(context);
    }

    public void Dispose()
    {
        _controller.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void About_ReturnsViewWithEnrollmentGroups()
    {
        var result = _controller.About() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<EnrollmentDateGroup>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void About_EnrollmentGroups_HaveCorrectCounts()
    {
        var result = _controller.About() as ViewResult;

        var model = Assert.IsType<List<EnrollmentDateGroup>>(result.Model);
        var group2020 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2020-09-01"));
        var group2021 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
        Assert.Equal(2, group2020.StudentCount);
        Assert.Equal(1, group2021.StudentCount);
    }

    [Fact]
