namespace ContosoUniversity.Tests.Helpers;

public static class TestHelper
{
    public static SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    public static Department AddDepartment(SchoolContext context, string name = "Engineering", decimal budget = 350000m, int? instructorId = null)
    {
        var dept = new Department
        {
            Name = name,
            Budget = budget,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = instructorId
        };
        context.Departments.Add(dept);
        context.SaveChanges();
        return dept;
    }

    public static Course AddCourse(SchoolContext context, int courseId, string title, int credits, int departmentId)
    {
        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId
        };
        context.Courses.Add(course);
        context.SaveChanges();
        return course;
    }

    public static Student AddStudent(SchoolContext context, string firstName = "Carson", string lastName = "Alexander", string enrollmentDate = "2010-09-01")
    {
        var student = new Student
        {
            FirstMidName = firstName,
            LastName = lastName,
            EnrollmentDate = DateTime.Parse(enrollmentDate)
        };
        context.Students.Add(student);
        context.SaveChanges();
        return student;
    }

