public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _sut;

    public NotificationServiceTests()
    {
        _sut = new NotificationService();
        // Drain any existing notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _sut.Dispose();
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        Assert.Null(_sut.ReceiveNotification());
    }

    [Fact]
    public void SendAndReceive_WithDisplayName_ReturnsCorrectNotification()
    {
        _sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("Student", result.EntityType);
        Assert.Equal("42", result.EntityId);
        Assert.Equal("CREATE", result.Operation);
        Assert.Equal("Admin", result.CreatedBy);
        Assert.False(result.IsRead);
        Assert.Contains("John Doe", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _sut.SendNotification("Course", "1", EntityOperation.UPDATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Equal("System", result.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "has been created")]
    [InlineData(EntityOperation.UPDATE, "has been updated")]
    [InlineData(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_OperationMessages_ContainExpectedPhrase(EntityOperation operation, string expectedPhrase)
    {
        _sut.SendNotification("Department", "5", "Engineering", operation);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains(expectedPhrase, result.Message);
        Assert.Contains("Engineering", result.Message);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _sut.SendNotification("Student", "99", EntityOperation.CREATE);

        var result = _sut.ReceiveNotification();

        Assert.NotNull(result);
        Assert.Contains("ID: 99", result.Message);
    }

    [Fact]
    public void ReceiveNotification_FIFO_Order()
    {
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);

        var first = _sut.ReceiveNotification();
        var second = _sut.ReceiveNotification();

        Assert.Equal("A", first.EntityType);
        Assert.Equal("B", second.EntityType);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        var exception = Record.Exception(() => _sut.MarkAsRead(999));

        Assert.Null(exception);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now;
        _sut.SendNotification("Test", "1", EntityOperation.CREATE);
