using Xunit;

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Theory]
    [InlineData(1, 10, 100, 10)]
    [InlineData(1, 10, 5, 1)]
    [InlineData(1, 3, 10, 4)]
    [InlineData(2, 5, 10, 2)]
    public void Constructor_SetsPageIndexAndTotalPages(int pageIndex, int pageSize, int count, int expectedTotalPages)
    {
        var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        Assert.Equal(pageIndex, list.PageIndex);
        Assert.Equal(expectedTotalPages, list.TotalPages);
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var list = new PaginatedList<string>(items, 10, 1, 5);

        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("c", list);
    }

    [Theory]
    [InlineData(1, false)]
    [InlineData(2, true)]
    [InlineData(5, true)]
    public void HasPreviousPage_ReturnsExpected(int pageIndex, bool expected)
    {
        var list = new PaginatedList<int>(new List<int>(), 100, pageIndex, 10);

        Assert.Equal(expected, list.HasPreviousPage);
    }

    [Theory]
    [InlineData(1, 100, 10, true)]
    [InlineData(10, 100, 10, false)]
    [InlineData(1, 5, 10, false)]
    [InlineData(1, 15, 10, true)]
    public void HasNextPage_ReturnsExpected(int pageIndex, int count, int pageSize, bool expected)
    {
        var list = new PaginatedList<int>(new List<int>(), count, pageIndex, pageSize);

        Assert.Equal(expected, list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 50).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(5, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]);
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(3, result.PageIndex);
        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
    }
}

