using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelper.CreateContext();
        _controller = CreateController(_context);
    }

    private static StudentsController CreateController(SchoolContext context)
    {
        var controller = new StudentsController(context);
        controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(),
            Mock.Of<ITempDataProvider>());
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithPaginatedList()
    {
        TestHelper.AddStudent(_context, "Alice", "Smith");
        TestHelper.AddStudent(_context, "Bob", "Jones");

        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Theory]
    [InlineData("name_desc", "Smith")]
    [InlineData("", "Jones")]
    [InlineData("Date", "Smith")]
    [InlineData("date_desc", "Jones")]
    public void Index_SortOrder_ReturnsSortedStudents(string sortOrder, string expectedFirstLastName)
    {
        TestHelper.AddStudent(_context, "Alice", "Jones", "2012-09-01");
        TestHelper.AddStudent(_context, "Bob", "Smith", "2010-09-01");

        var result = _controller.Index(sortOrder, null, null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(expectedFirstLastName, model[0].LastName);
    }

    [Fact]
    public void Index_SearchString_FiltersResults()
    {
        TestHelper.AddStudent(_context, "Alice", "Smith");
        TestHelper.AddStudent(_context, "Bob", "Jones");

        var result = _controller.Index(null, null, "Smith", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Smith", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        TestHelper.AddStudent(_context, "Alice", "Smith");
        TestHelper.AddStudent(_context, "Bob", "Jones");

        var result = _controller.Index(null, null, "Alice", null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Alice", model[0].FirstMidName);
    }

    [Fact]
    public void Index_NewSearchString_ResetsPageToOne()
    {
        TestHelper.AddStudent(_context, "Alice", "Smith");

        var result = _controller.Index(null, null, "Smith", 3) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        TestHelper.AddStudent(_context, "Alice", "Smith");
        TestHelper.AddStudent(_context, "Bob", "Jones");

        var result = _controller.Index(null, "Smith", null, null) as ViewResult;

        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.Equal("", (string)_controller.ViewBag.NameSortParm);
        Assert.Equal("Date", (string)_controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithNameSort_SetsDescendingSortParm()
    {
        var result = _controller.Index("", null, null, null) as ViewResult;

        Assert.Equal("name_desc", (string)_controller.ViewBag.NameSortParm);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        var student = TestHelper.AddStudent(_context);

        var result = _controller.Details(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Students);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student { EnrollmentDate = DateTime.Parse("2020-09-01") };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.Empty(_context.Students);
    }

    [Fact]
    public void Create_Post_DefaultEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_Post_EnrollmentDateTooEarly_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(1752, 1, 1)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = TestHelper.AddStudent(_context);

        var result = _controller.Edit(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = TestHelper.AddStudent(_context);
        _context.Entry(student).State = EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };

        var result = _controller.Edit(updatedStudent) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            ID = 1,
            EnrollmentDate = DateTime.Parse("2020-09-01")
        };

        var result = _controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_DefaultEnrollmentDate_AddsModelError()
    {
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = default
        };

        var result = _controller.Edit(student) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        var student = TestHelper.AddStudent(_context);

        var result = _controller.Delete(student.ID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(student.ID, model.ID);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesStudentAndRedirects()
    {
        var student = TestHelper.AddStudent(_context);

        var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Empty(_context.Students);
    }
}

