        var loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
    }

    private (Department dept, Course course) SeedCourseData()
    {
        var dept = TestHelper.AddDepartment(_context);
