using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestHelper.CreateContext();
        _controller = new DepartmentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        TestHelper.AddDepartment(_context);

        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<List<Department>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_WithMultipleDepartments_ReturnsAll()
    {
        TestHelper.AddDepartment(_context, "Engineering");
        TestHelper.AddDepartment(_context, "Mathematics");

        var result = _controller.Index() as ViewResult;

        var model = Assert.IsType<List<Department>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var dept = TestHelper.AddDepartment(_context);

        var result = _controller.Details(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        TestHelper.AddInstructor(_context);

        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Create POST ---

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = DateTime.Parse("2020-01-01")
        };

        var result = _controller.Create(department) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Single(_context.Departments);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        var result = _controller.Create(department) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_WithInstructor_SavesAssociation()
    {
        var instructor = TestHelper.AddInstructor(_context);
        var department = new Department
        {
            Name = "Science",
            Budget = 200000,
            StartDate = DateTime.Parse("2020-01-01"),
            InstructorID = instructor.ID
        };

        _controller.Create(department);

        var saved = _context.Departments.Single();
        Assert.Equal(instructor.ID, saved.InstructorID);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = TestHelper.AddDepartment(_context);

        var result = _controller.Edit(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = TestHelper.AddDepartment(_context);
        _context.Entry(dept).State = EntityState.Detached;

        var updated = new Department
        {
            DepartmentID = dept.DepartmentID,
            Name = "Updated",
            Budget = 500000,
            StartDate = DateTime.Parse("2020-01-01")
        };

        var result = _controller.Edit(updated) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1 };

        var result = _controller.Edit(department) as ViewResult;

        Assert.NotNull(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);

        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var dept = TestHelper.AddDepartment(_context);

        var result = _controller.Delete(dept.DepartmentID) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Department>(result.Model);
        Assert.Equal(dept.DepartmentID, model.DepartmentID);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    // --- Delete POST ---

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var dept = TestHelper.AddDepartment(_context);

        var result = _controller.DeleteConfirmed(dept.DepartmentID) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Departments.Find(dept.DepartmentID));
    }
}

