using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelper.CreateContext();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithInstructorData()
    {
        TestHelper.AddInstructor(_context);

        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Single(model.Instructors);
    }

    [Fact]
    public void Index_WithInstructorId_ShowsCourses()
    {
        var instructor = TestHelper.AddInstructor(_context);
        var dept = TestHelper.AddDepartment(_context);
        var course = TestHelper.AddCourse(_context, 1050, "Chemistry", 3, dept.DepartmentID);
        _context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });
        _context.SaveChanges();

        var result = _controller.Index(instructor.ID, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithoutInstructorId_CoursesIsNull()
    {
        TestHelper.AddInstructor(_context);

        var result = _controller.Index(null, null) as ViewResult;

        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Null(model.Courses);
    }

    [Fact]
